code.C:
#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long bytes; if(scanf("%lld", &bytes)!=1) break;
        double kb = bytes / 1024.0;
        double mb = bytes / (1024.0 * 1024.0);
        double gb = bytes / (1024.0 * 1024.0 * 1024.0);
        printf("%.2f\n%.2f\n%.2f\n", kb, mb, gb);
    }
    return 0;
}

