const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
if (input.length === 0) process.exit(0);
let t = parseInt(input[0], 10);
let idx = 1;
let out = [];
for (let i = 0; i < t; i++) {
  let bytes = Number(input[idx++]); // safe within double range for required output
  let kb = bytes / 1024.0;
  let mb = bytes / (1024.0 * 1024.0);
  let gb = bytes / (1024.0 * 1024.0 * 1024.0);
  out.push(kb.toFixed(2));
  out.push(mb.toFixed(2));
  out.push(gb.toFixed(2));
}
console.log(out.join('\n'));
